import React, { useState, useEffect, useCallback, useRef } from 'react';
import api from '../utils/api';

interface Message {
  id: string;
  canal: string;
  statut: string;
  sentAt: string;
  content?: string;
}

interface Lead {
  id: string;
  nom: string;
  email?: string;
  entreprise?: string;
  secteur?: string;
  score?: number;
  categorie?: string;
  statut: string;
  messages?: Message[];
}

interface Filters {
  search: string;
  categorie: string;
  statut: string;
  page: number;
}

const LIMIT = 20;

// Tier mapping: API enum value → display label + style
const TIER_LABEL: Record<string, string> = {
  CHAUD: 'Tier A',
  TIEDE: 'Tier B',
  FROID: 'Tier C',
};

const TIER_DOT: Record<string, string> = {
  CHAUD: 'bg-emerald-400',
  TIEDE: 'bg-blue-400',
  FROID: 'bg-zinc-500',
};

const TIER_TEXT: Record<string, string> = {
  CHAUD: 'text-emerald-400',
  TIEDE: 'text-blue-400',
  FROID: 'text-zinc-400',
};

const TIER_SCORE_COLOR: Record<string, string> = {
  CHAUD: 'text-emerald-400',
  TIEDE: 'text-blue-400',
  FROID: 'text-zinc-500',
};

const STATUT_COLORS: Record<string, string> = {
  NOUVEAU: 'border-zinc-700 text-zinc-400',
  CONTACTE: 'border-amber-700/60 text-amber-400',
  EN_COURS: 'border-indigo-700/60 text-indigo-400',
  CONVERTI: 'border-emerald-700/60 text-emerald-400',
  PERDU: 'border-red-700/60 text-red-400',
  BLACKLIST: 'border-zinc-800 text-zinc-600',
};

const STATUT_LABELS: Record<string, string> = {
  NOUVEAU: 'New',
  CONTACTE: 'Contacted',
  EN_COURS: 'In Progress',
  CONVERTI: 'Converted',
  PERDU: 'Lost',
  BLACKLIST: 'Blacklist',
};

const CATEGORIES = ['CHAUD', 'TIEDE', 'FROID'];
const STATUTS = ['NOUVEAU', 'CONTACTE', 'EN_COURS', 'CONVERTI', 'PERDU', 'BLACKLIST'];

function getScoreColor(score: number, categorie?: string): string {
  if (categorie) return TIER_SCORE_COLOR[categorie] || 'text-zinc-400';
  if (score >= 7) return 'text-emerald-400';
  if (score >= 4) return 'text-blue-400';
  return 'text-zinc-500';
}

function SearchIcon(): React.ReactElement {
  return (
    <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" />
    </svg>
  );
}

function PlusIcon(): React.ReactElement {
  return (
    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
      <line x1="12" y1="5" x2="12" y2="19" />
      <line x1="5" y1="12" x2="19" y2="12" />
    </svg>
  );
}

function ExportIcon(): React.ReactElement {
  return (
    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4" />
      <polyline points="7 10 12 15 17 10" />
      <line x1="12" y1="15" x2="12" y2="3" />
    </svg>
  );
}

function DotsIcon(): React.ReactElement {
  return (
    <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor">
      <circle cx="5" cy="12" r="1.5" />
      <circle cx="12" cy="12" r="1.5" />
      <circle cx="19" cy="12" r="1.5" />
    </svg>
  );
}

interface ActionMenuProps {
  leadId: string;
  onDelete: (id: string) => void;
}

function ActionMenu({ leadId, onDelete }: ActionMenuProps): React.ReactElement {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  return (
    <div className="relative" ref={ref}>
      <button
        onClick={() => setOpen((o) => !o)}
        className="opacity-0 group-hover:opacity-100 flex items-center justify-center w-6 h-6 rounded text-zinc-600 hover:text-zinc-300 hover:bg-zinc-800 transition-all"
      >
        <DotsIcon />
      </button>
      {open && (
        <div className="absolute right-0 top-full mt-1 w-36 bg-zinc-900 border border-zinc-800 rounded-lg shadow-xl z-20 py-1 overflow-hidden">
          <button
            onClick={() => { onDelete(leadId); setOpen(false); }}
            className="w-full flex items-center gap-2 px-3 py-2 text-xs text-red-400 hover:bg-red-500/10 transition-colors text-left"
          >
            Delete lead
          </button>
        </div>
      )}
    </div>
  );
}

export default function LeadsPage(): React.ReactElement {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [total, setTotal] = useState<number>(0);
  const [filters, setFilters] = useState<Filters>({ search: '', categorie: '', statut: '', page: 1 });
  const [loading, setLoading] = useState<boolean>(false);

  const fetchLeads = useCallback(async () => {
    setLoading(true);
    try {
      const params: Record<string, any> = { ...filters, limit: LIMIT };
      Object.keys(params).forEach((k) => !params[k] && delete params[k]);
      const { data } = await api.get('/leads', { params });
      setLeads(data.leads);
      setTotal(data.total);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [filters]);

  useEffect(() => {
    fetchLeads();
  }, [fetchLeads]);

  const deleteLead = async (id: string): Promise<void> => {
    if (!window.confirm('Delete this lead?')) return;
    await api.delete(`/leads/${id}`);
    fetchLeads();
  };

  const updateStatut = async (id: string, statut: string): Promise<void> => {
    await api.put(`/leads/${id}`, { statut });
    fetchLeads();
  };

  const from = (filters.page - 1) * LIMIT + 1;
  const to = Math.min(filters.page * LIMIT, total);

  return (
    <div className="flex flex-col h-full">
      {/* Top Bar */}
      <div className="px-6 py-4 border-b border-zinc-800/80 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <h1 className="text-sm font-semibold text-zinc-100 tracking-tight">Leads</h1>
          <span className="text-xs text-zinc-600 tabular-nums font-mono">{total} leads</span>
        </div>
        <div className="flex items-center gap-2">
          <a
            href="http://localhost:3001/export?format=csv"
            className="flex items-center gap-1.5 px-2.5 py-1.5 border border-zinc-800 text-zinc-500 hover:text-zinc-300 hover:border-zinc-700 text-xs font-medium rounded-md transition-colors"
          >
            <ExportIcon />
            Export CSV
          </a>
          <button className="flex items-center gap-1.5 px-2.5 py-1.5 bg-indigo-600 hover:bg-indigo-500 text-white text-xs font-medium rounded-md transition-colors">
            <PlusIcon />
            New Lead
          </button>
        </div>
      </div>

      {/* Filter Row */}
      <div className="px-6 py-3 border-b border-zinc-800/80 flex items-center gap-4">
        {/* Search — command bar style */}
        <div className="relative">
          <span className="absolute left-2.5 top-1/2 -translate-y-1/2 text-zinc-600 pointer-events-none">
            <SearchIcon />
          </span>
          <input
            className="pl-8 pr-3 py-1.5 bg-zinc-900 border border-zinc-800 rounded-md text-xs text-zinc-200 placeholder-zinc-600 focus:outline-none focus:border-zinc-600 w-60 transition-colors"
            placeholder="Search leads..."
            value={filters.search}
            onChange={(e) => setFilters({ ...filters, search: e.target.value, page: 1 })}
          />
        </div>

        {/* Tier text tabs */}
        <div className="flex items-center gap-0">
          <button
            onClick={() => setFilters({ ...filters, categorie: '', page: 1 })}
            className={`px-3 py-1.5 text-xs font-medium transition-colors border-b-2 ${
              filters.categorie === ''
                ? 'border-indigo-500 text-zinc-100'
                : 'border-transparent text-zinc-500 hover:text-zinc-300'
            }`}
          >
            All
          </button>
          {CATEGORIES.map((c) => (
            <button
              key={c}
              onClick={() => setFilters({ ...filters, categorie: filters.categorie === c ? '' : c, page: 1 })}
              className={`flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium transition-colors border-b-2 ${
                filters.categorie === c
                  ? 'border-indigo-500 text-zinc-100'
                  : 'border-transparent text-zinc-500 hover:text-zinc-300'
              }`}
            >
              <span className={`w-1.5 h-1.5 rounded-full ${TIER_DOT[c]}`} />
              {TIER_LABEL[c]}
            </button>
          ))}
        </div>

        {/* Status dropdown */}
        <select
          className="ml-auto px-2.5 py-1.5 bg-zinc-900 border border-zinc-800 rounded-md text-xs text-zinc-500 focus:outline-none focus:border-zinc-600 transition-colors"
          value={filters.statut}
          onChange={(e) => setFilters({ ...filters, statut: e.target.value, page: 1 })}
        >
          <option value="">All statuses</option>
          {STATUTS.map((s) => (
            <option key={s} value={s}>{STATUT_LABELS[s] || s}</option>
          ))}
        </select>
      </div>

      {/* Table */}
      <div className="flex-1 overflow-auto">
        <table className="w-full text-xs">
          <thead className="sticky top-0 bg-zinc-950 border-b border-zinc-800/80">
            <tr>
              {['Name', 'Company', 'Sector', 'Score', 'Tier', 'Status', 'Actions'].map((h) => (
                <th key={h} className="px-4 py-2.5 text-left text-[10px] text-zinc-600 font-medium uppercase tracking-widest">
                  {h}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr>
                <td colSpan={7} className="text-center py-16 text-zinc-600">
                  <div className="flex flex-col items-center gap-2">
                    <svg className="animate-spin w-4 h-4 text-zinc-700" viewBox="0 0 24 24" fill="none">
                      <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="2" strokeDasharray="40" strokeDashoffset="10" />
                    </svg>
                    <span className="text-[11px] text-zinc-700">Loading...</span>
                  </div>
                </td>
              </tr>
            ) : leads.length === 0 ? (
              <tr>
                <td colSpan={7} className="text-center py-20 text-zinc-700">
                  <div className="flex flex-col items-center gap-2">
                    <svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.25" strokeLinecap="round" strokeLinejoin="round" className="text-zinc-800">
                      <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
                      <circle cx="9" cy="7" r="4" />
                    </svg>
                    <p className="text-[11px] text-zinc-700">No leads found</p>
                  </div>
                </td>
              </tr>
            ) : (
              leads.map((lead) => (
                <tr
                  key={lead.id}
                  className="border-b border-zinc-800/40 hover:bg-zinc-900/30 transition-colors group"
                >
                  <td className="px-4 py-2.5 font-medium text-zinc-200 whitespace-nowrap">
                    {lead.nom}
                  </td>
                  <td className="px-4 py-2.5 text-zinc-500 whitespace-nowrap">
                    {lead.entreprise || <span className="text-zinc-700">—</span>}
                  </td>
                  <td className="px-4 py-2.5 text-zinc-500 whitespace-nowrap">
                    {lead.secteur || <span className="text-zinc-700">—</span>}
                  </td>
                  <td className="px-4 py-2.5">
                    <span
                      className={`font-mono font-semibold tabular-nums ${getScoreColor(lead.score ?? 0, lead.categorie)}`}
                    >
                      {lead.score != null ? lead.score.toFixed(1) : <span className="text-zinc-700">—</span>}
                    </span>
                  </td>
                  <td className="px-4 py-2.5">
                    {lead.categorie ? (
                      <span className={`flex items-center gap-1.5 ${TIER_TEXT[lead.categorie] || 'text-zinc-500'}`}>
                        <span className={`w-1.5 h-1.5 rounded-full flex-shrink-0 ${TIER_DOT[lead.categorie] || 'bg-zinc-600'}`} />
                        {TIER_LABEL[lead.categorie] || lead.categorie}
                      </span>
                    ) : (
                      <span className="text-zinc-700">—</span>
                    )}
                  </td>
                  <td className="px-4 py-2.5">
                    <select
                      className={`bg-transparent border border-transparent rounded px-1.5 py-0.5 text-xs font-medium cursor-pointer hover:border-zinc-700 transition-colors outline-none border-zinc-700/50 ${
                        STATUT_COLORS[lead.statut] || 'text-zinc-400'
                      }`}
                      value={lead.statut}
                      onChange={(e) => updateStatut(lead.id, e.target.value)}
                    >
                      {STATUTS.map((s) => (
                        <option key={s} value={s} className="bg-zinc-900 text-zinc-200">
                          {STATUT_LABELS[s] || s}
                        </option>
                      ))}
                    </select>
                  </td>
                  <td className="px-4 py-2.5">
                    <ActionMenu leadId={lead.id} onDelete={deleteLead} />
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      {total > 0 && (
        <div className="px-6 py-3 border-t border-zinc-800/80 flex items-center justify-between">
          <span className="text-xs text-zinc-600 tabular-nums font-mono">
            {from}–{to} of {total}
          </span>
          <div className="flex items-center gap-1">
            <button
              disabled={filters.page <= 1}
              onClick={() => setFilters({ ...filters, page: filters.page - 1 })}
              className="px-2.5 py-1 border border-zinc-800 rounded text-xs text-zinc-500 hover:text-zinc-300 hover:border-zinc-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
            >
              ← Prev
            </button>
            <span className="px-2.5 py-1 text-xs text-zinc-600 tabular-nums font-mono">
              {filters.page}
            </span>
            <button
              disabled={filters.page * LIMIT >= total}
              onClick={() => setFilters({ ...filters, page: filters.page + 1 })}
              className="px-2.5 py-1 border border-zinc-800 rounded text-xs text-zinc-500 hover:text-zinc-300 hover:border-zinc-700 disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
            >
              Next →
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
